import{_ as d}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o as l,c as p,b as r,a,e,w as n,d as h}from"./app-75fed8c6.js";const c={},s=a("h2",{id:"meshbasicmaterial",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#meshbasicmaterial","aria-hidden":"true"},"#"),e(" MeshBasicMaterial")],-1),f=a("p",null,"一个以简单着色（平面或线框）方式来绘制几何体的材质。这种材质不受光照的影响。",-1),u=h('<h2 id="构造器" tabindex="-1"><a class="header-anchor" href="#构造器" aria-hidden="true">#</a> 构造器</h2><h3 id="parameters-object" tabindex="-1"><a class="header-anchor" href="#parameters-object" aria-hidden="true">#</a> parameters : Object</h3><p>parameters - (可选)用于定义材质外观的对象，具有一个或多个属性。材质的任何属性都可以从此处传入(包括从Material继承的任何属性)</p><p>属性color例外，其可以作为十六进制字符串传递，默认情况下为 0xffffff（白色），内部调用Color.set(color)</p><h2 id="属性" tabindex="-1"><a class="header-anchor" href="#属性" aria-hidden="true">#</a> 属性</h2>',5),m=h('<h3 id="alphamap-texture" tabindex="-1"><a class="header-anchor" href="#alphamap-texture" aria-hidden="true">#</a> .alphaMap : Texture</h3><p>alpha贴图是一张灰度纹理，用于控制整个表面的不透明度。（黑色：完全透明；白色：完全不透明）。 默认值为null</p><p>仅使用纹理的颜色，忽略alpha通道（如果存在）。 对于RGB和RGBA纹理，WebGL渲染器在采样此纹理时将使用绿色通道， 因为在DXT压缩和未压缩RGB 565格式中为绿色提供了额外的精度。 Luminance-only以及luminance/alpha纹理也仍然有效</p><h3 id="aomap-texture" tabindex="-1"><a class="header-anchor" href="#aomap-texture" aria-hidden="true">#</a> .aoMap : Texture</h3><p>该纹理的红色通道用作环境遮挡贴图。默认值为null。aoMap需要第二组UV</p><h3 id="aomapintensity-float" tabindex="-1"><a class="header-anchor" href="#aomapintensity-float" aria-hidden="true">#</a> .aoMapIntensity : Float</h3><p>环境遮挡效果的强度。默认值为1。零是不遮挡效果</p><h3 id="color-color" tabindex="-1"><a class="header-anchor" href="#color-color" aria-hidden="true">#</a> .color : Color</h3><p>材质的颜色(Color)，默认值为白色 (0xffffff)</p><h3 id="combine-integer" tabindex="-1"><a class="header-anchor" href="#combine-integer" aria-hidden="true">#</a> .combine : Integer</h3><p>如何将表面颜色的结果与环境贴图（如果有）结合起来</p><p>选项为THREE.MultiplyOperation（默认值），THREE.MixOperation， THREE.AddOperation。如果选择多个，则使用.reflectivity在两种颜色之间进行混合</p><h3 id="envmap-texture" tabindex="-1"><a class="header-anchor" href="#envmap-texture" aria-hidden="true">#</a> .envMap : Texture</h3><p>环境贴图。默认值为null。</p><h3 id="fog-boolean" tabindex="-1"><a class="header-anchor" href="#fog-boolean" aria-hidden="true">#</a> .fog : Boolean</h3><p>材质是否受雾影响。默认为true。</p><h3 id="lightmap-texture" tabindex="-1"><a class="header-anchor" href="#lightmap-texture" aria-hidden="true">#</a> .lightMap : Texture</h3><p>光照贴图。默认值为null。lightMap需要第二组UV。</p><h3 id="lightmapintensity-float" tabindex="-1"><a class="header-anchor" href="#lightmapintensity-float" aria-hidden="true">#</a> .lightMapIntensity : Float</h3><p>烘焙光的强度。默认值为1。</p><h3 id="map-texture" tabindex="-1"><a class="header-anchor" href="#map-texture" aria-hidden="true">#</a> .map : Texture</h3><p>颜色贴图。可以选择包括一个alpha通道，通常与.transparent 或.alphaTest。默认为null。</p><h3 id="reflectivity-float" tabindex="-1"><a class="header-anchor" href="#reflectivity-float" aria-hidden="true">#</a> .reflectivity : Float</h3><p>环境贴图对表面的影响程度; 见.combine。默认值为1，有效范围介于0（无反射）和1（完全反射）之间。</p><h3 id="refractionratio-float" tabindex="-1"><a class="header-anchor" href="#refractionratio-float" aria-hidden="true">#</a> .refractionRatio : Float</h3><p>空气的折射率（IOR）（约为1）除以材质的折射率。它与环境映射模式THREE.CubeRefractionMapping 和THREE.EquirectangularRefractionMapping一起使用。 The index of refraction (IOR) of air (approximately 1) divided by the index of refraction of the material. It is used with environment mapping mode THREE.CubeRefractionMapping. 折射率不应超过1。默认值为0.98。</p><h3 id="specularmap-texture" tabindex="-1"><a class="header-anchor" href="#specularmap-texture" aria-hidden="true">#</a> .specularMap : Texture</h3><p>材质使用的高光贴图。默认值为null。</p><h3 id="wireframe-boolean" tabindex="-1"><a class="header-anchor" href="#wireframe-boolean" aria-hidden="true">#</a> .wireframe : Boolean</h3><p>将几何体渲染为线框。默认值为false（即渲染为平面多边形）。</p><h3 id="wireframelinecap-string" tabindex="-1"><a class="header-anchor" href="#wireframelinecap-string" aria-hidden="true">#</a> .wireframeLinecap : String</h3><p>定义线两端的外观。可选值为 &#39;butt&#39;，&#39;round&#39; 和 &#39;square&#39;。默认为&#39;round&#39;。</p><p>该属性对应2D Canvas lineJoin属性， 并且会被WebGL渲染器忽略。</p><h3 id="wireframelinejoin-string" tabindex="-1"><a class="header-anchor" href="#wireframelinejoin-string" aria-hidden="true">#</a> .wireframeLinejoin : String</h3><p>定义线连接节点的样式。可选值为 &#39;round&#39;, &#39;bevel&#39; 和 &#39;miter&#39;。默认值为 &#39;round&#39;。</p><p>该属性对应2D Canvas lineJoin属性， 并且会被WebGL渲染器忽略。</p><h3 id="wireframelinewidth-float" tabindex="-1"><a class="header-anchor" href="#wireframelinewidth-float" aria-hidden="true">#</a> .wireframeLinewidth : Float</h3><p>控制线框宽度。默认值为1。</p><p>由于OpenGL Core Profile与大多数平台上WebGL渲染器的限制， 无论如何设置该值，线宽始终为1。</p><h2 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h2>',40);function x(b,_){const o=i("IFrame"),t=i("RouterLink");return l(),p("div",null,[s,f,r(o,{url:"https://luotainxu-demo.netlify.app/#/threejs/material/meshBasicMaterial"}),u,a("p",null,[e("共有属性请参见其基类"),r(t,{to:"/threejs/%E6%9D%90%E8%B4%A8/%E6%9D%90%E8%B4%A8.html"},{default:n(()=>[e("Material")]),_:1})]),m,a("p",null,[e("共有方法请参见其基类"),r(t,{to:"/threejs/%E6%9D%90%E8%B4%A8/%E6%9D%90%E8%B4%A8.html"},{default:n(()=>[e("Material")]),_:1})])])}const M=d(c,[["render",x],["__file","基础网格材质.html.vue"]]);export{M as default};
